namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }

    public string FullCode => $"{DepartmentCode} {CourseNumber}";
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, quantity, structure, and space." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published extensively on CS education.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming).", Credits = 4, Schedule = "TTh 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research focuses on algorithm optimization and competitive programming pedagogy.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "310", Title = "Database Systems", Description = "Introduction to relational databases, SQL, normalization, and transaction processing.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked in industry for 10 years before joining academia, specializing in distributed database systems.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "251", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, eigenvalues, and applications.", Credits = 3, Schedule = "TTh 1:00–2:20 PM", InstructorName = "Dr. Elena Volkov", InstructorBio = "Dr. Volkov's research spans numerical linear algebra and machine learning foundations.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, waves, and thermodynamics with laboratory component.", Credits = 4, Schedule = "MWF 10:00–10:50 AM, Lab: Th 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres brings NASA research experience to the classroom and mentors undergraduate research projects.", IsFeatured = true },
            new() { Id = 7, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "TTh 9:00–10:20 AM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres brings NASA research experience to the classroom and mentors undergraduate research projects.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "110", Title = "College Writing", Description = "Develop critical reading and academic writing skills through essay composition and peer review.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Prof. Diana Hughes", InstructorBio = "Prof. Hughes is a published author and writing workshop leader with 20 years of teaching experience.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "TTh 3:00–4:20 PM", InstructorName = "Prof. Marcus Bell", InstructorBio = "Prof. Bell specializes in 20th-century American fiction and has authored two critical studies.", IsFeatured = false },
            new() { Id = 10, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural exchanges from prehistory to 1500 CE.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Fatima Al-Said", InstructorBio = "Dr. Al-Said is an archaeologist and historian whose fieldwork spans the Middle East and Mediterranean.", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null, int? credits = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (credits.HasValue)
            query = query.Where(c => c.Credits == credits.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.FullCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

