arguments.file_text:
@page "/"
@inject CourseCatalog.Services.CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome! Browse our departments and courses, or search for something specific.</p>

<section class="featured-courses">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <h3><a href="/courses/@course.Id">@course.FullCode — @course.Title</a></h3>
                <p>@course.Credits credits · @course.Schedule</p>
                <p>@course.InstructorName</p>
            </div>
        }
    </div>
</section>

<section class="departments">
    <h2>Departments</h2>
    <ul class="department-list">
        @foreach (var dept in departments)
        {
