                <th>Credits</th>
                <th>Schedule</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.FullCode</td>
                    <td><a href="/courses/@course.Id">@course.Title</a></td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td>@course.InstructorName</td>
                    <td><a href="/enroll?courseId=@course.Id">Enroll</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }
    [SupplyParameterFromQuery] public int? Credits { get; set; }

    private List<CourseCatalog.Models.Department> departments = new();
    private List<CourseCatalog.Models.Course> courses = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId, Credits);
    }
}

@page "/courses/{Id:int}"
@inject CourseCatalog.Services.CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist. <a href="/courses">Browse all courses</a>.</p>
}
else
{
    <PageTitle>@course.FullCode — @course.Title</PageTitle>

    <nav class="breadcrumb">
        <a href="/">Home</a> &gt; <a href="/courses">Courses</a> &gt; @course.FullCode
    </nav>

    <h1>@course.FullCode — @course.Title</h1>

    <div class="course-detail">
        <section>
            <h2>Description</h2>
            <p>@course.Description</p>
        </section>

        <section>
            <h2>Details</h2>
            <dl>
                <dt>Credits</dt>
                <dd>@course.Credits</dd>
                <dt>Schedule</dt>
                <dd>@course.Schedule</dd>
                <dt>Department</dt>
                <dd>@course.DepartmentCode</dd>
            </dl>
        </section>

        <section>
            <h2>Instructor</h2>
            <p><strong>@course.InstructorName</strong></p>
            <p>@course.InstructorBio</p>
        </section>

        <a href="/enroll?courseId=@course.Id" class="enroll-link">Request Enrollment</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private CourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@inject CourseCatalog.Services.CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="confirmation">
        <h2>Request Submitted</h2>
        <p>Thank you, <strong>@Model.StudentName</strong>! Your enrollment request for
            <strong>@selectedCourse?.FullCode — @selectedCourse?.Title</strong> has been received.</p>
        <p>You will receive a confirmation at your university email.</p>
        <a href="/courses">Browse more courses</a>
    </div>
}
else
{
    <form method="post" action="/enroll">
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required
                   placeholder="e.g., S12345678" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                        @course.FullCode — @course.Title (@course.Credits cr)
                    </option>
                }
            </select>
        </div>

        <button type="submit">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public CourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<CourseCatalog.Models.Course> courses = new();
    private CourseCatalog.Models.Course? selectedCourse;
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;

        // Check if this is a POST (form was submitted)
        if (!string.IsNullOrEmpty(Model.StudentName) && !string.IsNullOrEmpty(Model.StudentId) && Model.CourseId > 0)
        {
            selectedCourse = Catalog.GetCourse(Model.CourseId);
            submitted = true;
        }
    }
}

