arguments.new_str:
/* Base styles */
html, body {
    font-family: 'Segoe UI', 'Helvetica Neue', Helvetica, Arial, sans-serif;
    margin: 0;
    padding: 0;
    color: #333;
    line-height: 1.6;
}

a {
    color: #1a5276;
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

/* Header */
.site-header {
    background-color: #1a5276;
    color: white;
    padding: 1rem 2rem;
}

.site-header nav {
    display: flex;
    align-items: center;
    gap: 2rem;
    max-width: 1200px;
    margin: 0 auto;
}

.site-title {
    color: white;
    font-size: 1.3rem;
    font-weight: bold;
}

.site-title:hover {
    text-decoration: none;
}

.nav-links {
    list-style: none;
    display: flex;
    gap: 1.5rem;
    margin: 0;
    padding: 0;
}

.nav-links a {
    color: #d4e6f1;
}

.nav-links a:hover {
    color: white;
}

/* Main content */
.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem;
}

/* Homepage */
.lead {
    font-size: 1.15rem;
    color: #555;
}

.featured-courses {
    margin: 2rem 0;
}

.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.5rem;
    margin-top: 1rem;
}

.course-card {
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 1.25rem;
    background: #f8f9fa;
}

.course-card h3 {
    margin: 0 0 0.5rem;
    font-size: 1.05rem;
}

.course-card p {
    margin: 0.25rem 0;
    font-size: 0.9rem;
    color: #555;
}

.departments {
    margin: 2rem 0;
}

.department-list {
    list-style: none;
    padding: 0;
}

.department-list li {
    padding: 0.75rem 0;
    border-bottom: 1px solid #eee;
}

/* Course table */
.search-filters {
    display: flex;
    gap: 0.75rem;
    flex-wrap: wrap;
    margin-bottom: 1.5rem;
}

.search-filters input,
.search-filters select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

.search-filters input {
    flex: 1;
    min-width: 200px;
}

.search-filters button {
    padding: 0.5rem 1.25rem;
    background: #1a5276;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.search-filters button:hover {
    background: #154360;
}

.course-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 1rem;
}

.course-table th,
.course-table td {
    padding: 0.75rem;
    text-align: left;
    border-bottom: 1px solid #eee;
}

.course-table th {
    background: #f8f9fa;
    font-weight: 600;
}

.course-table tr:hover {
    background: #f0f4f8;
}

/* Course detail */
.breadcrumb {
    font-size: 0.9rem;
    margin-bottom: 1rem;
    color: #666;
}

.course-detail section {
    margin: 1.5rem 0;
}

.course-detail dl {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 0.5rem 1.5rem;
}

.course-detail dt {
    font-weight: 600;
}

.enroll-link {
    display: inline-block;
    margin-top: 1rem;
    padding: 0.6rem 1.5rem;
    background: #1a5276;
    color: white;
    border-radius: 4px;
}

.enroll-link:hover {
    background: #154360;
    color: white;
    text-decoration: none;
}

/* Enrollment form */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 600;
}

.form-group input,
.form-group select {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

form button[type="submit"] {
    padding: 0.6rem 1.5rem;
    background: #1a5276;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
}

form button[type="submit"]:hover {
    background: #154360;
}

.confirmation {
    background: #d4edda;
    border: 1px solid #c3e6cb;
    border-radius: 6px;
    padding: 1.5rem;
}

.confirmation h2 {
    color: #155724;
    margin-top: 0;
}

/* Footer */
.site-footer {
    margin-top: 3rem;
    padding: 1.5rem 2rem;
    background: #f8f9fa;
    border-top: 1px solid #eee;
    text-align: center;
    font-size: 0.9rem;
    color: #666;
}

