 @page "/enroll"
 @inject CourseCatalog.Services.CatalogService Catalog

 <PageTitle>Enrollment Request</PageTitle>

 <h1>Enrollment Request</h1>

 @if (submitted)
 {
     <div class="confirmation">
         <h2>Request Submitted</h2>
         <p>Thank you, <strong>@Model.StudentName</strong>! Your enrollment request for
             <strong>@selectedCourse?.FullCode — @selectedCourse?.Title</strong> has been received.</p>
         <p>You will receive a confirmation at your university email.</p>
         <a href="/courses">Browse more courses</a>
     </div>
 }
 else
 {
     <form method="post" action="/enroll">
         <AntiforgeryToken />

         <div class="form-group">
             <label for="studentName">Full Name</label>
             <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
         </div>

         <div class="form-group">
             <label for="studentId">Student ID</label>
             <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required
                    placeholder="e.g., S12345678" />
         </div>

         <div class="form-group">
             <label for="courseId">Course</label>
             <select id="courseId" name="Model.CourseId" required>
                 <option value="">— Select a course —</option>
                 @foreach (var course in courses)
                 {
                     <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                         @course.FullCode — @course.Title (@course.Credits cr)
                     </option>
                 }
             </select>
         </div>

         <button type="submit">Submit Enrollment Request</button>
     </form>
 }

 @code {
     [SupplyParameterFromForm] public CourseCatalog.Models.EnrollmentRequest? Model { get; set; }
     [SupplyParameterFromQuery] public int? CourseId { get; set; }

     private List<CourseCatalog.Models.Course> courses = new();
     private CourseCatalog.Models.Course? selectedCourse;
     private bool submitted;

     protected override void OnInitialized()
     {
         Model ??= new();
         courses = Catalog.GetCourses();

         if (CourseId.HasValue && Model.CourseId == 0)
             Model.CourseId = CourseId.Value;

         // Check if this is a POST (form was submitted)
         if (!string.IsNullOrEmpty(Model.StudentName) && !string.IsNullOrEmpty(Model.StudentId) && Model.CourseId > 0)
         {
             selectedCourse = Catalog.GetCourse(Model.CourseId);
             submitted = true;
         }
     }
 }

